void rebalance(std::vector<int>& nums, int& height) {
    if (height < 1) {
        return;
    }
    for (int i = height - 1; i >= 0; --i) {
        if (nums[2 * i + 1] > nums[2 * i + 2]) {
            std::swap(nums[2 * i], nums[2 * i + 1]);
        }
    }
    if (height > 0 && nums[0] > nums[1]) {
        height += 1;
    }
    return;
}

void insert(std::vector<int>& nums, int& height) {
    nums.push_back(10);
    rebalance(nums, height);
    return;
}

